args.command:
python3 -c "
import csv
from collections import defaultdict
d=defaultdict(list)
with open('disease_relevant_inhibited_all_normalized_ode/repeat_variability_analysis_20260704_2021/average_curves_by_setting.csv') as f:
    r=csv.DictReader(f)
    for row in r:
        d[row['setting']].append((float(row['time']),float(row['mean_y'])))
def t50(pts):
    for t,y in pts:
        if y>=0.5: return t
    return None
def t10(pts):
    for t,y in pts:
        if y>=0.1: return t
    return None
def t90(pts):
    for t,y in pts:
        if y>=0.9: return t
    return None
for k in d:
    pts=sorted(d[k])
    print(k,'t10',round(t10(pts) or -1,3),'t50',round(t50(pts) or -1,3),'t90',round(t90(pts) or -1,3))
"

